#[AutowiredService]
final class SimpleXMLElementClassPropertyReflectionExtension implements PropertiesClassReflectionExtension
{

	public function hasProperty(ClassReflection $classReflection, string $propertyName): bool
	{
		return $classReflection->is('SimpleXMLElement');
	}

	public function getProperty(ClassReflection $classReflection, string $propertyName): PropertyReflection
	{
		return new SimpleXMLElementProperty($propertyName, $classReflection, new BenevolentUnionType([new ObjectType($classReflection->getName()), new NullType()]));
	}

}

foreach ($parts as $part) {
    [$pathPrefix, $location] = $part;
    if (str_starts_with($path, $pathPrefix)) {
        $path = $location.substr($path, \strlen($pathPrefix));
        // Only set X-Accel-Redirect header if a valid URI can be produced
        // as nginx does not serve arbitrary file paths.
        $this->headers->set($type, rawurlencode($path));
        $this->maxlen = 0;
        break;
    }
}

if (isset($params['path'])) {
    if ($isMemory) {
        throw new Exception(
            'Invalid connection settings: specifying both parameters "path" and "memory" is ambiguous.',
        );
    }

    $filename = $params['path'];
} elseif ($isMemory) {
    $filename = ':memory:';
} else {
    throw new Exception(
        'Invalid connection settings: specify either the "path" or the "memory" parameter for SQLite3.',
    );
}

class ExtensionCompilerPass implements CompilerPassInterface
{
    public function process(ContainerBuilder $container): void
    {
        foreach ($container->getExtensions() as $extension) {
            if (!$extension instanceof CompilerPassInterface) {
                continue;
            }

            $extension->process($container);
        }
    }
}

class BeanstalkdTransportFactory implements TransportFactoryInterface
{
    public function createTransport(#[\SensitiveParameter] string $dsn, array $options, SerializerInterface $serializer): TransportInterface
    {
        unset($options['transport_name']);

        return new BeanstalkdTransport(Connection::fromDsn($dsn, $options), $serializer);
    }

    public function supports(#[\SensitiveParameter] string $dsn, array $options): bool
    {
        return str_starts_with($dsn, 'beanstalkd://');
    }
}

final class Arc
{
    public function __construct(
        public readonly string $place,
        public readonly int $weight,
    ) {
        if ($weight < 1) {
            throw new \InvalidArgumentException(\sprintf('The weight must be greater than 0, %d given.', $weight));
        }
        if ('' === $place) {
            throw new \InvalidArgumentException('The place name cannot be empty.');
        }
    }
}

final class TypeArgumentCountError extends Exception implements TypesException
{
    public static function new(string $name, ArgumentCountError $previous): self
    {
        return new self(
            sprintf(
                'To register "%s" pass an instance to `Type::addType` instead.',
                $name,
            ),
            previous: $previous,
        );
    }
}

final class SoapClientMethodsClassReflectionExtension implements MethodsClassReflectionExtension
{

	public function hasMethod(ClassReflection $classReflection, string $methodName): bool
	{
		return $classReflection->is('SoapClient');
	}

	public function getMethod(ClassReflection $classReflection, string $methodName): MethodReflection
	{
		return new SoapClientMethodReflection($classReflection, $methodName);
	}

}

class ResolvedTypeFactoryDataCollectorProxy implements ResolvedFormTypeFactoryInterface
{
    public function __construct(
        private ResolvedFormTypeFactoryInterface $proxiedFactory,
        private FormDataCollectorInterface $dataCollector,
    ) {
    }

    public function createResolvedType(FormTypeInterface $type, array $typeExtensions, ?ResolvedFormTypeInterface $parent = null): ResolvedFormTypeInterface
    {
        return new ResolvedTypeDataCollectorProxy(
            $this->proxiedFactory->createResolvedType($type, $typeExtensions, $parent),
            $this->dataCollector
        );
    }
}

class HtmlSanitizerExtension extends AbstractExtension
{
    public function __construct(
        private ContainerInterface $sanitizers,
        private string $defaultSanitizer = 'default',
    ) {
    }

    protected function loadTypeExtensions(): array
    {
        return [
            new Type\TextTypeHtmlSanitizerExtension($this->sanitizers, $this->defaultSanitizer),
        ];
    }
}

class PasswordHasherExtension extends AbstractExtension
{
    public function __construct(
        private PasswordHasherListener $passwordHasherListener,
    ) {
    }

    protected function loadTypeExtensions(): array
    {
        return [
            new Type\FormTypePasswordHasherExtension($this->passwordHasherListener),
            new Type\PasswordTypePasswordHasherExtension($this->passwordHasherListener),
        ];
    }
}

if ($package->id === -1) {
    // fixed package was not added to the pool as it did not pass the stability requirements, this is fine
    if ($this->pool->isUnacceptableFixedOrLockedPackage($package)) {
        continue;
    }

    // otherwise, looks like a bug
    throw new \LogicException("Fixed package ".$package->getPrettyString()." was not added to solver pool.");
}

if ($proxy->isSecure()) {
    if (!extension_loaded('openssl')) {
        throw new TransportException('You must enable the openssl extension to use a secure proxy.');
    }
    if ($isHttpsRequest) {
        throw new TransportException('You must enable the curl extension to make https requests through a secure proxy.');
    }
} elseif ($isHttpsRequest && !extension_loaded('openssl')) {
    throw new TransportException('You must enable the openssl extension to make https requests through a proxy.');
}

while ($this->transactionNestingLevel !== 0) {
    if ($this->autoCommit === false && $this->transactionNestingLevel === 1) {
        // When in no auto-commit mode, the last nesting commit immediately starts a new transaction.
        // Therefore we need to do the final commit here and then leave to avoid an infinite loop.
        $this->commit();

        return;
    }

    $this->commit();
}

foreach ($meta as $resource) {
    foreach ($this->resourceCheckers as $checker) {
        if (!$checker->supports($resource)) {
            continue; // next checker
        }
        if ($checker->isFresh($resource, $time)) {
            break; // no need to further check this resource
        }

        return false; // cache is stale
    }
    // no suitable checker found, ignore this resource
}

if (str_starts_with($e->getCode(), '23')) {
    // Retrieve finished session data written by concurrent connection by restarting the loop.
    // We have to start a new transaction as a failed query will mark the current transaction as
    // aborted in PostgreSQL and disallow further queries within it.
    $this->rollback();
    $this->beginTransaction();
    continue;
}

if ($isPlugin && 0 === \count($requires)) {
    // plugins with no dependencies go to the very front
    array_unshift($pluginsNoDeps, $op);
} else {
    // capture the requirements for this package so those packages will be moved up as well
    $pluginRequires = array_merge($pluginRequires, $requires);
    // move the operation to the front
    array_unshift($pluginsWithDeps, $op);
}

foreach ($distUrls as $index => $url) {
    $processedUrl = $this->processUrl($package, $url);
    $urls[$index] = [
        'base' => $url,
        'processed' => $processedUrl,
        // we use the complete download url here to avoid conflicting entries
        // from different packages, which would potentially allow a given package
        // in a third party repo to pre-populate the cache for the same package in
        // packagist for example.
        'cacheKey' => $cacheKeyGenerator($package, $processedUrl),
    ];
}

final class InvalidDriverClass extends InvalidArgumentException
{
    public static function new(string $driverClass): self
    {
        return new self(
            sprintf(
                'The given driver class %s has to implement the %s interface.',
                $driverClass,
                Driver::class,
            ),
        );
    }
}

final class InvalidWrapperClass extends InvalidArgumentException
{
    public static function new(string $wrapperClass): self
    {
        return new self(
            sprintf(
                'The given wrapper class %s has to be a subtype of %s.',
                $wrapperClass,
                Connection::class,
            ),
        );
    }
}

final class InvalidColumnDefinition extends LogicException implements SchemaException
{
    public static function nameNotSpecified(): self
    {
        return new self('Column name is not specified.');
    }

    public static function dataTypeNotSpecified(UnqualifiedName $columnName): self
    {
        return new self(sprintf('Data type is not specified for column %s.', $columnName->toString()));
    }
}

final class InvalidTableDefinition extends LogicException implements SchemaException
{
    public static function nameNotSet(): self
    {
        return new self('Table name is not set.');
    }

    public static function columnsNotSet(OptionallyQualifiedName $tableName): self
    {
        return new self(sprintf('Columns are not set for table %s.', $tableName->toString()));
    }
}

final class InvalidUniqueConstraintDefinition extends LogicException implements SchemaException
{
    public static function columnNamesAreNotSet(?UnqualifiedName $constraintName): self
    {
        return new self(sprintf(
            'Column names are not set for unique constraint %s.',
            $constraintName === null ? '<unnamed>' : $constraintName->toString(),
        ));
    }
}

final class InvalidViewDefinition extends LogicException implements SchemaException
{
    public static function nameNotSet(): self
    {
        return new self('View name is not set.');
    }

    public static function sqlNotSet(OptionallyQualifiedName $viewName): self
    {
        return new self(sprintf('SQL is not set for view %s.', $viewName->toString()));
    }
}

class InvalidName extends InvalidArgumentException implements Exception
{
    public static function forUnqualifiedName(int $count): self
    {
        return new self(sprintf('An unqualified name must consist of one identifier, %d given.', $count));
    }

    public static function forOptionallyQualifiedName(int $count): self
    {
        return new self(
            sprintf('An optionally qualified name must consist of one or two identifiers, %d given.', $count),
        );
    }
}

if ($originalNode instanceof Node\Stmt\Interface_) {
	$description = 'an interface';
} elseif ($originalNode instanceof Node\Stmt\Class_) {
	$description = 'a class';
} elseif ($originalNode instanceof Node\Stmt\Enum_) {
	$description = 'an enum';
} elseif ($originalNode instanceof Node\Stmt\Trait_) {
	throw new ShouldNotHappenException();
} elseif ($originalNode instanceof Node\Stmt\ClassMethod) {
	$description = 'a method';
}

final class InputValidationFailedException extends RuntimeException
{
    public function __construct(
        string $message,
        private readonly ConstraintViolationListInterface $violations,
    ) {
        parent::__construct($message);
    }

    public function getViolations(): ConstraintViolationListInterface
    {
        return $this->violations;
    }
}

if ($preferredChoices instanceof PropertyPathInterface) {
    $preferredChoices = static function ($choice) use ($accessor, $preferredChoices) {
        try {
            return $accessor->getValue($choice, $preferredChoices);
        } catch (UnexpectedTypeException) {
            // Assume not preferred if not readable
            return false;
        }
    };
}

if (preg_match($regex, $pattern, $matches)) {
    $formatter->setPattern($matches[0]);

    foreach ($timestamps as $timestamp => $choice) {
        $formattedTimestamps[$formatter->format($timestamp)] = $choice;
    }

    // I'd like to clone the formatter above, but then we get a
    // segmentation fault, so let's restore the old state instead
    $formatter->setPattern($pattern);
}

class UnsupportedMessageTypeException extends LogicException
{
    public function __construct(string $transport, string $supported, MessageInterface $given)
    {
        $message = \sprintf(
            'The "%s" transport only supports instances of "%s" (instance of "%s" given).',
            $transport,
            $supported,
            get_debug_type($given)
        );

        parent::__construct($message);
    }
}

foreach ($map['files'] as $fileIdentifier => $file) {
    // exclude laminas/laminas-zendframework-bridge:src/autoload.php as it breaks Composer in some conditions
    // see https://github.com/composer/composer/issues/10349 and https://github.com/composer/composer/issues/10401
    // this hack can be removed once this deprecated package stop being installed
    if ($fileIdentifier === '7e9bd612cc444b3eed788ebbe46263a0') {
        continue;
    }
    \Composer\Autoload\composerRequire($fileIdentifier, $file);
}

if ($isFirstItem) {
    $isFirstItem = false;
    // depending on the first elements key the generator is detected as a list or map
    // we can not check for a whole list or map because that would hurt the performance
    // of the streamed response which is the main goal of this response class
    if (0 !== $key) {
        $startTag = '{';
    }

    echo $startTag;
} else {
    // if not first element of the generic, a separator is required between the elements
    echo ',';
}

if ($rules === null) {
    if (!$this->io->isInteractive()) {
        throw new \RuntimeException(
            'Your composer.lock was generated before the allow-plugins security feature was introduced and your composer.json does not define allow-plugins. '
            . 'Run "composer update --lock" locally and commit the updated composer.lock, then add an explicit allow-plugins section to composer.json. '
            . 'See https://getcomposer.org/allow-plugins'
        );
    }

    // keep going and prompt the user
    $rules = [];
}

if (!$isDeprecationNotice) {
    // ignore some newly introduced warnings in new php versions until dependencies
    // can be fixed as we do not want to abort execution for those
    if (in_array($level, [E_WARNING, E_USER_WARNING], true) && str_contains($message, 'should either be used or intentionally ignored by casting it as (void)')) {
        self::outputWarning('Ignored new PHP warning but it should be reported and fixed: '.$message.' in '.$file.':'.$line, true);

        return true;
    }

    throw new \ErrorException($message, 0, $level, $file, $line);
}

if ($preserveVacuousConditionals) {
	$conditionalExpressions = $this->preserveVacuousConditionalExpressions(
		$conditionalExpressions,
		$this->conditionalExpressions,
		$theirExpressionTypes,
	);
	$conditionalExpressions = $this->preserveVacuousConditionalExpressions(
		$conditionalExpressions,
		$otherScope->conditionalExpressions,
		$ourExpressionTypes,
	);
}

foreach ($operators as $operator => $length) {
    // Collisions of character operators:
    // - an operator that begins with a character must have a space or a parenthesis before or starting at the beginning of a string
    // - an operator that ends with a character must be followed by a whitespace or a parenthesis
    $regex[] =
        (ctype_alpha($operator[0]) ? '(?<=^|[\s(])' : '')
        .preg_quote($operator, '/')
        .(ctype_alpha($operator[$length - 1]) ? '(?=[\s(])' : '');
}

if (\strlen($expiry) === \strlen($now) ? $expiry > $now : \strlen($expiry) < \strlen($now)) {
    // if a future-placed message is popped because of a race condition with
    // another running consumer, the message is readded to the queue

    if (!$this->rawCommand('ZADD', 'NX', $expiry, $queuedMessage)) {
        throw new TransportException('Could not add a message to the redis stream.');
    }

    break;
}

if (null === $translator) {
    $translator = new class implements TranslatorInterface, LocaleAwareInterface {
        use TranslatorTrait;
    };
    // Force the locale to be 'en' when no translator is provided rather than relying on the Intl default locale
    // This avoids depending on Intl or the stub implementation being available. It also ensures that Symfony
    // validation messages are pluralized properly even when the default locale gets changed because they are in
    // English.
    $translator->setLocale('en');
}
